SELECT role_name
FROM roles
WHERE role_id = 0;

SELECT COUNT(*) AS total_token_types, token_type_name, description
FROM token_types
GROUP BY token_type_name, description;

SELECT 
  (SELECT COUNT(DISTINCT user_id) FROM users WHERE role = 'admin') AS distinct_admin_users,
  (SELECT COUNT(DISTINCT credential_id) FROM credentials WHERE is_active = 1) AS distinct_active_credentials;

SELECT COUNT(*) AS total_credentials 
FROM credentials 
WHERE is_active = 1 AND created_at > '2023-04-01 00:00:00' AND token_type = 'password';

SELECT COUNT(credential_id) AS credential_count, token_type, created_at
FROM credentials
GROUP BY token_type, created_at;

SELECT COUNT(*) AS successful_access_count
FROM access_logs
WHERE access_type = 'use' AND access_result = 'success';

SELECT COUNT(*) AS successful_access_count
FROM access_logs
WHERE access_type = 'use' AND access_result = 'success';
